INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Standing_Pelvic_Tilt','Standing Pelvic Tilt','espalda baja',ARRAY['glúteos'],NULL,'stretching',ARRAY['Start off with your feet hip-distance apart.','Bend your knees slightly to keep them soft and springy.','You may want to move your pelvis forward and backward and back few times before holding the tailbone forward in this stretch.'],'Start off with your feet hip-distance apart. Bend your knees slightly to keep them soft and springy. You may want to move your pelvis forward and backward and back few times before holding the tailbone forward in this stretch.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Pelvic_Tilt/0.jpg','exercisedb',true),('Standing_Rope_Crunch','Standing Rope Crunch','abdominales',ARRAY[]::text[],'cable','strength',ARRAY['Attach a rope to a high pulley and select an appropriate weight.','Stand with your back to the cable tower. Take the rope with both hands over your shoulders, holding it to your upper chest. This will be your starting position.','Perform the movement by flexing the spine, crunching the weight down as far as you can.','Hold the peak contraction for a moment before returning to the starting position.'],'Attach a rope to a high pulley and select an appropriate weight. Stand with your back to the cable tower. Take the rope with both hands over your shoulders, holding it to your upper chest. This will be your starting position. Perform the movement by flexing the spine, crunching the weight down as far as you can. Hold the peak contraction for a moment before returning to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Rope_Crunch/0.jpg','exercisedb',true),('Standing_Soleus_And_Achilles_Stretch','Standing Soleus And Achilles Stretch','pantorrillas',ARRAY[]::text[],NULL,'stretching',ARRAY['Stand with your feet hip-distance apart, one foot slightly in front of the other.','Bend both knees, keeping your back heel on the floor. Switch sides.'],'Stand with your feet hip-distance apart, one foot slightly in front of the other. Bend both knees, keeping your back heel on the floor. Switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Soleus_And_Achilles_Stretch/0.jpg','exercisedb',true),('Standing_Toe_Touches','Standing Toe Touches','isquiotibiales',ARRAY['pantorrillas'],NULL,'stretching',ARRAY['Stand with some space in front and behind you.','Bend at the waist, keeping your legs straight, until you can relax and let your upper body hang down in front of you. Let your arms and hands hang down naturally. Hold for 10 to 20 seconds.'],'Stand with some space in front and behind you. Bend at the waist, keeping your legs straight, until you can relax and let your upper body hang down in front of you. Let your arms and hands hang down naturally. Hold for 10 to 20 seconds.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Toe_Touches/0.jpg','exercisedb',true),('Standing_Towel_Triceps_Extension','Standing Towel Triceps Extension','tríceps',ARRAY[]::text[],'peso corporal','strength',ARRAY['To begin, stand up with both arms fully extended above the head holding one end of a towel with both hands. Your elbows should be in and the arms perpendicular to the floor with the palms facing each other while your feet should be shoulder width apart from each other. This is the starting position.','Now communicate with your partner so that he/she can grip the other side of the towel to apply resistance. Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.','Go back to the starting position by using the triceps to raise the towel. Breathe out as you perform this step.','Repeat for the recommended amount of repetitions.'],'To begin, stand up with both arms fully extended above the head holding one end of a towel with both hands. Your elbows should be in and the arms perpendicular to the floor with the palms facing each other while your feet should be shoulder width apart from each other. This is the starting position. Now communicate with your partner so that he/she can grip the other side of the towel to apply resistance. Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step. Go back to the starting position by using the triceps to raise the towel. Breathe out as you perform this step. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Towel_Triceps_Extension/0.jpg','exercisedb',true),('Standing_Two-Arm_Overhead_Throw','Standing Two-Arm Overhead Throw','hombros',ARRAY['pecho','dorsales'],'balón medicinal','plyometrics',ARRAY['Stand with your feet shoulder width apart holding a medicine ball in both hands. To begin, reach the medicine ball deep behind your head as you bend the knees slightly and lean back.','Violently throw the ball forward, flexing at the hip and using your whole body to complete the movement.','The medicine ball can be thrown to a partner or to a wall, receiving it as it bounces back.'],'Stand with your feet shoulder width apart holding a medicine ball in both hands. To begin, reach the medicine ball deep behind your head as you bend the knees slightly and lean back. Violently throw the ball forward, flexing at the hip and using your whole body to complete the movement. The medicine ball can be thrown to a partner or to a wall, receiving it as it bounces back.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Two-Arm_Overhead_Throw/0.jpg','exercisedb',true),('Star_Jump','Star Jump','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales','hombros'],'peso corporal','plyometrics',ARRAY['Begin in a relaxed stance with your feet shoulder width apart and hold your arms close to the body.','To initiate the move, squat down halfway and explode back up as high as possible. Fully extend your entire body, spreading your legs and arms away from the body.','As you land, bring your limbs back in and absorb your impact through the legs.'],'Begin in a relaxed stance with your feet shoulder width apart and hold your arms close to the body. To initiate the move, squat down halfway and explode back up as high as possible. Fully extend your entire body, spreading your legs and arms away from the body. As you land, bring your limbs back in and absorb your impact through the legs.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Star_Jump/0.jpg','exercisedb',true),('Step-up_with_Knee_Raise','Step-up with Knee Raise','glúteos',ARRAY['isquiotibiales','cuádriceps'],'peso corporal','strength',ARRAY['Stand facing a box or bench of an appropriate height with your feet together. This will be your starting position.','Begin the movement by stepping up, putting your left foot on the top of the bench. Extend through the hip and knee of your front leg to stand up on the box. As you stand on the box with your left leg, flex your right knee and hip, bringing your knee as high as you can.','Reverse this motion to step down off the box, and then repeat the sequence on the opposite leg.'],'Stand facing a box or bench of an appropriate height with your feet together. This will be your starting position. Begin the movement by stepping up, putting your left foot on the top of the bench. Extend through the hip and knee of your front leg to stand up on the box. As you stand on the box with your left leg, flex your right knee and hip, bringing your knee as high as you can. Reverse this motion to step down off the box, and then repeat the sequence on the opposite leg.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Step-up_with_Knee_Raise/0.jpg','exercisedb',true),('Step_Mill','Step Mill','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales'],'máquina','cardio',ARRAY['To begin, step onto the stepmill and select the desired option from the menu. You can choose a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Use caution so that you don''''t trip as you climb the stairs. It is recommended that you maintain your grip on the handles so that you don''''t fall.','Stepmills offer convenience, cardiovascular benefits, and usually have less impact than running outside while offering a similar rate of calories burned. They are typically much harder than other cardio equipment. A 150 lb person will typically burn over 300 calories in 30 minutes, compared to about 175 calories walking.'],'To begin, step onto the stepmill and select the desired option from the menu. You can choose a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Use caution so that you don''t trip as you climb the stairs. It is recommended that you maintain your grip on the handles so that you don''t fall. Stepmills offer convenience, cardiovascular benefits, and usually have less impact than running outside while offering a similar rate of calories burned. They are typically much harder than other cardio equipment. A 150 lb person will typically burn over 300 calories in 30 minutes, compared to about 175 calories walking.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Step_Mill/0.jpg','exercisedb',true),('Stiff-Legged_Barbell_Deadlift','Stiff-Legged Barbell Deadlift','isquiotibiales',ARRAY['glúteos','espalda baja'],'barra','strength',ARRAY['Grasp a bar using an overhand grip (palms facing down). You may need some wrist wraps if using a significant amount of weight.','Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position.','Keeping the knees stationary, lower the barbell to over the top of your feet by bending at the hips while keeping your back straight. Keep moving forward as if you were going to pick something from the floor until you feel a stretch on the hamstrings. Inhale as you perform this movement.','Start bringing your torso up straight again by extending your hips until you are back at the starting position. Exhale as you perform this movement.','Repeat for the recommended amount of repetitions.'],'Grasp a bar using an overhand grip (palms facing down). You may need some wrist wraps if using a significant amount of weight. Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position. Keeping the knees stationary, lower the barbell to over the top of your feet by bending at the hips while keeping your back straight. Keep moving forward as if you were going to pick something from the floor until you feel a stretch on the hamstrings. Inhale as you perform this movement. Start bringing your torso up straight again by extending your hips until you are back at the starting position. Exhale as you perform this movement. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Stiff-Legged_Barbell_Deadlift/0.jpg','exercisedb',true);